import os
import time
from typing import Optional, Dict, Any

from flask import Flask, request, Response
from prometheus_client import (
    CollectorRegistry,
    Counter,
    Histogram,
    generate_latest,
    CONTENT_TYPE_LATEST,
)

APP_NAME = os.getenv("APP_NAME", "traffic_app")
METRICS_PATH = os.getenv("METRICS_PATH", "/metrics")
HOST = os.getenv("HOST", "0.0.0.0")
PORT = int(os.getenv("PORT", "8000"))

MAX_UNIQUE_USER_PATH = int(os.getenv("MAX_UNIQUE_USER_PATH", "50000"))
MAX_UNIQUE_SESSION = int(os.getenv("MAX_UNIQUE_SESSION", "200000"))
MAX_PATH_LEN = int(os.getenv("MAX_PATH_LEN", "2048"))

REQUEST_DURATION_BUCKETS = (
    0.001,
    0.0025,
    0.005,
    0.01,
    0.025,
    0.05,
    0.1,
    0.25,
    0.5,
    1.0,
    2.5,
    5.0,
    10.0,
)

app = Flask(APP_NAME)
registry = CollectorRegistry(auto_describe=True)

http_requests_total = Counter(
    "http_requests_total",
    "Total HTTP requests",
    labelnames=("user_id", "session_id", "path", "method", "status"),
    registry=registry,
)

http_request_duration_seconds = Histogram(
    "http_request_duration_seconds",
    "HTTP request duration in seconds",
    labelnames=("user_id", "session_id", "path", "method", "status"),
    buckets=REQUEST_DURATION_BUCKETS,
    registry=registry,
)

user_path_requests_total = Counter(
    "user_path_requests_total",
    "Total HTTP requests by unique user-path combination",
    labelnames=("user_id", "path"),
    registry=registry,
)

_unique_user_path = set()
_unique_session = set()

dropped_user_path_total = Counter(
    "dropped_user_path_metric_total",
    "Number of times a new unique user-path series was dropped due to cardinality limits",
    registry=registry,
)

dropped_session_total = Counter(
    "dropped_session_label_total",
    "Number of times a new session_id label was dropped due to cardinality limits",
    registry=registry,
)

dropped_user_total = Counter(
    "dropped_user_label_total",
    "Number of times a new user_id label was dropped due to cardinality limits",
    registry=registry,
)

cardinality_limits = Counter(
    "label_cardinality_limit_total",
    "Cardinality limit hits by type",
    labelnames=("type",),
    registry=registry,
)


def _get_user_id() -> str:
    v = request.headers.get("X-User-Id") or request.args.get("user_id") or "anonymous"
    return str(v)[:256]


def _get_session_id() -> str:
    v = request.headers.get("X-Session-Id") or request.args.get("session_id") or "none"
    return str(v)[:256]


def _full_path() -> str:
    path = request.full_path if request.query_string else request.path
    if path.endswith("?"):
        path = path[:-1]
    return path[:MAX_PATH_LEN]


def _maybe_limit_session(session_id: str) -> str:
    if session_id in _unique_session:
        return session_id
    if len(_unique_session) < MAX_UNIQUE_SESSION:
        _unique_session.add(session_id)
        return session_id
    dropped_session_total.inc()
    cardinality_limits.labels("session_id").inc()
    return "__dropped__"


def _maybe_limit_user(user_id: str) -> str:
    if user_id == "anonymous":
        return user_id
    # Soft-limit users indirectly via user-path cap; keep user label if already seen in any user-path
    # Without separate tracking, accept user_id unless user-path is capped.
    return user_id


def _track_user_path(user_id: str, path: str) -> None:
    key = (user_id, path)
    if key in _unique_user_path:
        user_path_requests_total.labels(user_id=user_id, path=path).inc()
        return
    if len(_unique_user_path) < MAX_UNIQUE_USER_PATH:
        _unique_user_path.add(key)
        user_path_requests_total.labels(user_id=user_id, path=path).inc()
        return
    dropped_user_path_total.inc()
    cardinality_limits.labels("user_path").inc()


@app.route(METRICS_PATH, methods=["GET"])
def metrics() -> Response:
    data = generate_latest(registry)
    return Response(data, mimetype=CONTENT_TYPE_LATEST)


@app.route("/", defaults={"u_path": ""}, methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
@app.route("/<path:u_path>", methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
def all_routes(u_path: str) -> Response:
    start = time.perf_counter()

    user_id = _get_user_id()
    session_id = _get_session_id()
    path = _full_path()

    session_id_limited = _maybe_limit_session(session_id)
    user_id_limited = _maybe_limit_user(user_id)

    status_code = 200
    try:
        if request.method == "OPTIONS":
            status_code = 204
            resp = Response("", status=status_code)
        else:
            resp = Response("ok", status=status_code, mimetype="text/plain")
        return resp
    finally:
        duration = time.perf_counter() - start
        status = str(status_code)
        method = request.method

        http_requests_total.labels(
            user_id=user_id_limited,
            session_id=session_id_limited,
            path=path,
            method=method,
            status=status,
        ).inc()

        http_request_duration_seconds.labels(
            user_id=user_id_limited,
            session_id=session_id_limited,
            path=path,
            method=method,
            status=status,
        ).observe(duration)

        _track_user_path(user_id_limited, path)


def main() -> None:
    app.run(host=HOST, port=PORT, threaded=True)


if __name__ == "__main__":
    main()